from docx import Document
from docx.shared import Pt, Inches
from docx.enum.text import WD_LINE_SPACING
doc = Document('output/governance-diligence-memo.docx')
# margins
for s in doc.sections:
    s.top_margin = Inches(0.7); s.bottom_margin = Inches(0.7)
    s.left_margin = Inches(0.85); s.right_margin = Inches(0.85)
# tighten body spacing a touch more
for p in doc.paragraphs:
    sn = p.style.name if p.style else ''
    pf = p.paragraph_format
    if sn.startswith('Heading'):
        if sn == 'Heading 1': pf.space_before=Pt(9); pf.space_after=Pt(2)
        elif sn == 'Heading 2': pf.space_before=Pt(7); pf.space_after=Pt(2)
        elif sn == 'Heading 3': pf.space_before=Pt(5); pf.space_after=Pt(1)
        elif sn == 'Heading 4': pf.space_before=Pt(4); pf.space_after=Pt(1)
    elif sn not in ('Title',):
        if sn == 'Compact':
            pf.space_after = Pt(0)
        else:
            pf.space_after = Pt(3)
        pf.line_spacing = 1.03
        pf.line_spacing_rule = WD_LINE_SPACING.MULTIPLE
doc.save('output/governance-diligence-memo.docx')
print('tightened')
